mapper.select:
SELECT diaryno, memberno, title, content, password, rdate, file1, file1saved, thumb1, size1, risk_flag
FROM diary
WHERE diaryno = #{diaryno}

mapper.update:
UPDATE diary
SET title = #{title},
content = #{content},
rdate = sysdate,
risk_flag = #{risk_flag}

    , file1 = #{file1}


    , file1saved = #{file1saved}


    , thumb1 = #{thumb1}


    , size1 = #{size1}

WHERE diaryno = #{diaryno}

mapper.select:
SELECT risk_flag AS riskFlag, COUNT(*) AS count
FROM diary
WHERE memberno = #{memberno}
AND rdate BETWEEN #{startDate} AND #{endDate}
GROUP BY risk_flag

SELECT COUNT(*)
FROM diary
WHERE memberno = #{memberno}
AND EXTRACT(YEAR FROM rdate) = #{year}
AND EXTRACT(MONTH FROM rdate) = #{month}

SELECT *
FROM diary
WHERE memberno = #{memberno}
AND EXTRACT(YEAR FROM rdate) = #{year}
AND EXTRACT(MONTH FROM rdate) = #{month}
ORDER BY rdate DESC
OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY
